const envelope = JSON.parse($json.stdout || '{}');
const payload = JSON.parse(envelope.stdout || '{}');
const status = Number(envelope.status || 0);
const base = {
  status,
  telegram_chat_id: $env.TELEGRAM_CHAT_ID || '',
  payload,
};
if (status === 20 || payload.ok === false) {
  return [{
    json: {
      ...base,
      route_type: 'error',
      error_text: [
        'YouTube post repeater failed.',
        `Channel: ${payload.channel || 'unknown'}`,
        `Exit status: ${status}`,
        payload.error ? `Error: ${payload.error}` : 'Error: CLI returned a non-success status without an error message.',
      ].join('\n'),
    },
  }];
}
return [{
  json: {
    ...base,
    route_type: 'posts',
  },
}];

const payload = $json.payload || {};
return (payload.posts || []).map((post, index) => ({
  json: {
    channel: payload.channel,
    fetched_at: payload.fetched_at,
    post_index: index,
    telegram_chat_id: $json.telegram_chat_id,
    ...post,
  },
}));
